// Translated OpenMP Target Offload code example:

#include <cstdio>
#include <cstdlib>

#define N 1024*1024

int main() {
    float *data = (float*) malloc(N * sizeof(float));
    if (!data) {
        fprintf(stderr, "Failed to allocate host memory\n");
        return -1;
    }

    // Initialize data
    for (int i = 0; i < N; i++) {
        data[i] = (float)i;
    }

    // Offload computation to device
    #pragma omp target data map(tofrom: data[0:N])
    {
        #pragma omp target teams distribute parallel for thread_limit(256)
        for (int i = 0; i < N; i++) {
            data[i] = data[i] * 2.0f;
        }
    }

    // Verify results
    int errors = 0;
    for (int i = 0; i < N; i++) {
        if (data[i] != (float)(i*2)) {
            errors++;
            if (errors < 10) {
                printf("Error at index %d: %f != %f\n", i, data[i], (float)(i*2));
            }
        }
    }
    if (errors == 0) {
        printf("Test PASSED\n");
    } else {
        printf("Test FAILED with %d errors\n", errors);
    }

    free(data);
    return 0;
}
